import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def calculate_arrival_time(distance):
        return current_time + distance / truck_speed

    best_node = None
    best_score = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer_pos)
        arrival_time = calculate_arrival_time(distance)
        open_window, close_window = time_windows[idx]

        time_penalty = max(0, arrival_time - close_window) + max(0, open_window - arrival_time)
        other_truck_distances = [calculate_distance(truck_pos, customer_pos) for truck_pos in all_truck_pos if not np.array_equal(truck_pos, cur_truck_pos)]

        if len(other_truck_distances) > 0:
            nearest_other_truck_distance = min(other_truck_distances)
        else:
            nearest_other_truck_distance = 0

        synchronization_factor = (nearest_other_truck_distance / truck_speed) / 10  # Reducing impact by factor of 10
        score = distance + time_penalty * 10 + synchronization_factor

        if score < best_score:
            best_score = score
            best_node = idx

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def estimate_travel_time(distance, traffic_index):
        return distance / (truck_speed * traffic_index)

    traffic_data = np.random.uniform(0.7, 1.3, len(unvisited_customers))  # Simulates variable traffic conditions
    best_node = None
    minimum_time_cost = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        distance = np.linalg.norm(cur_truck_pos - customer_pos)
        traffic_index = traffic_data[idx]
        estimated_time = estimate_travel_time(distance, traffic_index)
        total_travel_time = current_time + estimated_time

        start_time, end_time = time_windows[idx]
        if total_travel_time < start_time:
            wait_time = start_time - total_travel_time
            time_to_start = total_travel_time + wait_time
        elif total_travel_time > end_time:
            penalty_time = (total_travel_time - end_time) * 10
            time_to_start = current_time + penalty_time
        else:
            time_to_start = total_travel_time

        time_cost = time_to_start + estimated_time
        if time_cost < minimum_time_cost:
            minimum_time_cost = time_cost
            best_node = idx

    return best_node
